import heapq
from itertools import islice
from sympy import primerange
def A002473gen(p=7): # generate all p-smooth terms
    v, oldv, h, psmooth_primes, heaps = 1, 0, [1], list(primerange(1, p+1)), {1}
    while True:
        v = heapq.heappop(h)
        if v != oldv:
            yield v
            oldv = v
            for p in psmooth_primes:
                if (m:=v*p) not in heaps:
                    heapq.heappush(h, m)
                    heaps.add(m)
        heaps.discard(v)
